    }
}

class IoTDeviceRepository(
    private val client: IoTHttpClient
) {
    fun fetchDeviceStatus(deviceIp: String, callback: IoTHttpClient.HttpCallback) {
        client.get("http://$deviceIp/status", callback)
    }

    fun sendDeviceCommand(deviceIp: String, commandJson: String, callback: IoTHttpClient.HttpCallback) {
        client.post("http://$deviceIp/command", IoTRequestBodies.json(commandJson), callback)
    }

    fun fetchCloudDevices(callback: IoTHttpClient.HttpCallback) {
        client.getCloud("/devices", callback)
    }

    fun updateCloudDevice(deviceId: String, payloadJson: String, callback: IoTHttpClient.HttpCallback) {
        client.postCloud("/devices/$deviceId", IoTRequestBodies.json(payloadJson), callback)
    }
